const raw = $input.first().json;
const body = raw.body || raw;

// Avito v3.0.0 wraps in payload.value
const payload = body.payload || body;
const value = payload.value || body.value || body;

// Skip non-text/non-message types
if (payload.type && payload.type !== 'message') {
  return [{ json: { skip: true, reason: 'not a message: ' + payload.type } }];
}
if (value.type && value.type !== 'text') {
  return [{ json: { skip: true, reason: 'not text: ' + value.type } }];
}

const chatId = value.chat_id || value.chatId || '';
const authorId = String(value.author_id || value.authorId || '');
const msgId = value.id || '';
const text = value.content?.text || value.text || '';
const itemId = String(value.item_id || value.itemId || body.item_id || '');

if (!chatId || !text) {
  return [{ json: { skip: true, reason: 'no chatId or text', debug: JSON.stringify(body).slice(0,500) } }];
}

return [{ json: { chatId, authorId, msgId, text, itemId, skip: false } }];

const token = $('Get Token').first().json.access_token;
const userId = String($input.first().json.id);
const parsed = $('Parse Incoming').first().json;

// Don't reply to our own messages
if (parsed.authorId === userId) {
  return [{ json: { skip: true, reason: 'own message' } }];
}

// Dedup: don't reply to same message twice
const store = $getWorkflowStaticData('global');
if (!store.replied) store.replied = {};
if (store.replied[parsed.chatId] === parsed.msgId) {
  return [{ json: { skip: true, reason: 'already replied' } }];
}

return [{ json: { skip: false, token, userId, chatId: parsed.chatId, msgId: parsed.msgId, lastText: parsed.text, itemId: parsed.itemId || '' } }];

const itemData = $input.first().json;
const title = (itemData.title || itemData.name || '').toLowerCase();
const categoryName = (itemData.category?.name || '').toLowerCase();
const hay = title + ' ' + categoryName;

// Keywords that indicate this is our training/courses listing
const trainingKeywords = [
  'курс', 'курсы', 'обучен', 'школ', 'уроки', 'урок', 'занят',
  'монтаж', 'видеомонт', 'видеомейк', 'видеоредактор',
  'premiere', 'after effects', 'davinci', 'final cut',
  'нейрос', 'нейросет', 'ии ', ' ии', 'искусствен', 'ai ', 'ai,', 'chatgpt',
  'midjourney', 'kling', 'suno', 'sora',
  'репетитор', 'преподават', 'наставн', 'ментор',
  'студия че', 'studiya che', 'studia che'
];

const isTraining = trainingKeywords.some(kw => hay.includes(kw));

// Pass through all fields + flag
return [{ json: { ...itemData, isTrainingItem: isTraining, itemTitle: itemData.title || itemData.name || '', itemCategoryName: itemData.category?.name || '' } }];

const ctx = $('Merge Context').first().json;
const msgs = ($('Get Chat History').first().json.messages || []).slice().reverse();

const conversation = msgs
  .filter(m => m.content?.text)
  .map(m => ({
    role: String(m.author_id) === String(ctx.userId) ? 'assistant' : 'user',
    content: m.content.text
  }));

// Ensure last message is from user
if (!conversation.length || conversation[conversation.length-1].role !== 'user') {
  conversation.push({ role: 'user', content: ctx.lastText });
}

// Item info (which ad they wrote from)
const itemData = $('Get Item Info').first().json;
const itemTitle = itemData.title || itemData.name || '';
const itemCategory = itemData.category?.name || '';
const itemLine = itemTitle ? `\n\nОБЪЯВЛЕНИЕ: Человек написал по объявлению «${itemTitle}»${itemCategory ? ' (категория: ' + itemCategory + ')' : ''}. Отвечай с учётом этого контекста.` : '';

// Get shared config from site-chat workflow
const siteConf = $input.first().json;
const basePrompt = siteConf.basePrompt || 'Ты — ассистент платформы Студия ЧЕ по видеомонтажу и ИИ.';
const courses = siteConf.courses || [];

const coursesList = courses.map((c,i) => `${i+1}. "${c.name}" — ${c.price}${c.level ? ' ('+c.level+')' : ''}`).join('\n');

// --- Sales role: загружается из static data (редактируется через TG/PWA),
// с дефолтом при пустом значении. Editable key: store.avitoConfig.salesPrompt
const DEFAULT_SALES_ROLE = `РОЛЬ: Ты — менеджер по продажам высшего класса в Студии ЧЕ. Не бот, а живой профессионал: уверенный, внимательный, располагающий. Твоя задача — помочь человеку решить его задачу через наш продукт и мягко довести до покупки.

СТИЛЬ ОБЩЕНИЯ НА АВИТО:
- ВСЕГДА обращайся на «Вы» (с большой буквы). Это деловое общение.
- 2-4 предложения. Без воды, без формальностей, без «Здравствуйте, я представитель...». Сразу по делу, живо, по-человечески.
- Пиши как опытный продавец в переписке: короткие предложения, без канцелярита, без смайликов более 1 на сообщение.

ЛОГИКА ПРОДАЖ:
1. ПЕРВОЕ СООБЩЕНИЕ клиента — выясни контекст: что человеку нужно, какая цель (блог, работа, хобби, новая профессия). Не вываливай сразу курсы — задай 1 короткий уточняющий вопрос.
2. ВЫЯСНИВ ПОТРЕБНОСТЬ — подбери 1-2 курса из списка, которые реально ему подходят. Объясни ЧТО человек получит (навык, результат, через сколько), а не формальное «что входит».
3. ЦЕНА — называй сразу и уверенно, как только спросят. Никогда не уходи от ответа. Формат: «Курс X — Y рублей. Оплата единоразово, доступ навсегда».
4. ВОЗРАЖЕНИЯ — работай мягко: «дорого» → покажи ценность (стоимость 1-2 заказов на фрилансе окупает). «Подумаю» → «Что конкретно смущает? Могу помочь разобраться». «Справлюсь сам» → уважай выбор, но напомни про структуру и поддержку.
5. ДОПРОДАЖА — если человек интересуется одним курсом, упомяни связанный (например, купили монтаж → предложи ИИ-инструменты как следующий шаг).
6. ЗАКРЫТИЕ — когда клиент готов («интересно», «как оплатить», «беру»), добавь SEND_SITE_LINK в конец ответа. Ссылка даст ему страницу курса и форму оплаты.

ТЕМАТИКА (ЖЁСТКО):
- Ты отвечаешь ТОЛЬКО про наши курсы, видеомонтаж, нейросети, контент, работу видеомейкера и смежные темы.
- Если клиент спрашивает про другое (погода, политика, личное, посторонние услуги, несвязанные товары) — вежливо скажи одним предложением что по этим вопросам не консультируешь, и верни разговор к обучению. Пример: «По этому вопросу подсказать не смогу, я специализируюсь на наших курсах по видеомонтажу и нейросетям. Если интересно обучение — расскажу».
- Не поддерживай долгий офф-топик даже если клиент настаивает.

ЖЁСТКИЕ ПРАВИЛА:
- НИКОГДА не выдумывай цены, курсы, условия, даты стартов или характеристики, которых нет в списке выше.
- Если не знаешь ответа — честно скажи «Этот момент уточню у преподавателя и вернусь» и не придумывай.
- Не обещай скидок без подтверждения.
- SEND_SITE_LINK добавляй ТОЛЬКО когда клиент явно готов (купить, оплатить, записаться, посмотреть подробно, изучить программу). НЕ добавляй в первых ответах и при общих вопросах.`;

const store = $getWorkflowStaticData('global');
if (!store.avitoConfig) store.avitoConfig = {};
const salesRole = (store.avitoConfig.salesPrompt && String(store.avitoConfig.salesPrompt).trim().length > 100)
  ? String(store.avitoConfig.salesPrompt)
  : DEFAULT_SALES_ROLE;

const systemPrompt = basePrompt + '\n\nКУРСЫ НА ПЛАТФОРМЕ:\n' + coursesList + itemLine + '\n\n' + salesRole;

const body = JSON.stringify({
  model: 'gpt-4o-mini',
  messages: [{ role: 'system', content: systemPrompt }, ...conversation],
  max_tokens: 350,
  temperature: 0.7
});

return [{ json: { gptBody: body, token: ctx.token, userId: ctx.userId, chatId: ctx.chatId, msgId: ctx.msgId, usedOverride: salesRole !== DEFAULT_SALES_ROLE } }];

const gptRes = $input.first().json;
const prev = $('Prepare GPT Body').first().json;
let reply = gptRes.choices?.[0]?.message?.content?.trim() || 'Добрый день! Чем могу помочь? 😊';

const sendLink = reply.includes('SEND_SITE_LINK');
reply = reply.replace('SEND_SITE_LINK', '').trim();

return [{ json: { reply, sendLink, token: prev.token, userId: prev.userId, chatId: prev.chatId, msgId: prev.msgId } }];

const ctx = $('Extract Reply').first().json;
const store = $getWorkflowStaticData('global');
if (!store.replied) store.replied = {};
store.replied[ctx.chatId] = ctx.msgId;
const keys = Object.keys(store.replied);
if (keys.length > 500) {
  keys.slice(0, keys.length - 500).forEach(k => delete store.replied[k]);
}
return [{ json: { ok: true } }];
